#include <stdio.h>
int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    int freq[M + 1] = {0};
    int arr[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &arr[i]);
        freq[arr[i]]++;
    }
    int permCount = 0;
    int prevType = arr[0];
    int count = 1;
    for (int i = 1; i < N; i++) {
        if (arr[i] != prevType) {
            permCount += count - 1;
            count = 1;
            prevType = arr[i];
        } else {
            count++;
        }
    }
    permCount += count - 1;
    printf("%d\n", permCount);
    return 0;
}

